const FOCUSABLE = 'button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])';

export function trapFocus(container: HTMLElement, returnTo?: HTMLElement): () => void {
  const focusables = Array.from(container.querySelectorAll<HTMLElement>(FOCUSABLE));
  const first = focusables[0];
  const last = focusables[focusables.length - 1];

  function onKey(e: KeyboardEvent) {
    if (e.key !== 'Tab') return;
    if (e.shiftKey && document.activeElement === first) {
      last?.focus(); e.preventDefault();
    } else if (!e.shiftKey && document.activeElement === last) {
      first?.focus(); e.preventDefault();
    }
  }

  function onEsc(e: KeyboardEvent) {
    if (e.key === 'Escape') {
      container.dispatchEvent(new CustomEvent('a11y:close', { bubbles: true }));
    }
  }

  container.addEventListener('keydown', onKey);
  container.addEventListener('keydown', onEsc);
  first?.focus();

  return () => {
    container.removeEventListener('keydown', onKey);
    container.removeEventListener('keydown', onEsc);
    returnTo?.focus();
  };
}
